{
  "name": "conversation-esaa",
  "version": "1.3.0",
  "description": "Installer and lifecycle manager for Conversation ESAA",
  "type": "module",
  "bin": {
    "conversation-esaa": "src/cli.js"
  },
  "files": [
    "src/",
    ".conversation-esaa/bin/*.ps1",
    "LICENSE",
    "PRIVACY.md"
  ],
  "scripts": {
    "test": "node --test tests/installer/*.test.js",
    "test:bootstrap": "pwsh -NoProfile -File tests/test-installer-bootstrap.ps1"
  },
  "engines": {
    "node": ">=18"
  },
  "keywords": [
    "agents",
    "conversation",
    "esaa",
    "installer"
  ],
  "license": "MIT",
  "repository": {
    "type": "git",
    "url": "git+https://github.com/elzobrito/conversation-esaa.git"
  }
}
